import { Component } from "react";
import './Navbar.css'

class Navbar extends Component {
    render(){
        const { secciones } = this.props
        return(
            <div className="navbar">
                {secciones.map(x => 
                    <a key={x} href={'#' + x} className="elemento-navbar">
                        {x}
                    </a>
                )}
            </div>

        )
    }
}

export default Navbar
